I'll generate behaviorally anchored proficiency levels for each skill in the Culinary Craft category. Let me create observable, differentiated descriptions for each level.

<function_calls>
<invoke name="add_proficiency_levels">
<parameter name="levels_json">[
  {
    "skill_name": "Heat & Cooking Methods",
    "category": "Culinary Craft",
    "cluster": "Cooking Techniques",
    "skill_description": "Applies dry, moist, and combination heat methods correctly across diverse ingredients and dishes.",
    "levels": [
      {
        "level": 1,
        "level_name": "Foundational",
        "level_description": "Follows established heat settings and cooking times for standard recipes under supervision. Recognizes basic dry, moist, and combination methods and identifies when each applies to familiar dishes."
      },
      {
        "level": 2,
        "level_name": "Competent",
        "level_description": "Independently selects and executes appropriate heat methods for routine menu items, adjusting temperature and timing based on ingredient properties and desired outcomes. Consistently produces properly cooked proteins, vegetables, and starches within service standards."
      },
      {
        "level": 3,
        "level_name": "Expert",
        "level_description": "Strategically orchestrates complex heat sequences and multi-method preparations to enhance texture, flavor, and visual appeal across non-standard ingredients and dishes. Diagnoses and corrects cooking problems in real-time, mentors others in method selection, and innovates techniques that optimize consistency and quality."
      }
    ]
  },
  {
    "skill_name": "Knife Skills",
    "category": "Culinary Craft",
    "cluster": "Cooking Techniques",
    "skill_description": "Performs precision cuts, filleting, and butchery with speed, consistency, and safety.",
    "levels": [
      {
        "level": 1,
        "level_name": "Foundational",
        "level_description": "Executes basic cuts (dice, julienne, chiffonade) with guidance on technique and safety protocols. Demonstrates proper grip and knife maintenance while producing cuts of acceptable but inconsistent size and uniformity."
      },
      {
        "level": 2,
        "level_name": "Competent",
